import React, { useState, useEffect } from 'react';
import { dishAPI, restaurantAPI, reviewAPI } from '../services/api';
import RestaurantDetail from './RestaurantDetail';

const CustomerDashboard = ({ user, onLogout }) => {
  const [restaurants, setRestaurants] = useState([]);
  const [selectedRestaurant, setSelectedRestaurant] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('');
  const [filteredRestaurants, setFilteredRestaurants] = useState([]);

  useEffect(() => {
    loadRestaurants();
  }, []);

  useEffect(() => {
    filterRestaurants();
  }, [restaurants, searchTerm]);





  const loadRestaurants = async () => {
    try {
      const response = await restaurantAPI.getAll();
      setRestaurants(response.data);
    } catch (error) {
      console.error('Error loading restaurants:', error);
    }
  };

  const searchDishes = async () => {
    try {
      const response = await dishAPI.search(searchTerm);
      setFilteredDishes(response.data);
    } catch (error) {
      console.error('Error searching dishes:', error);
    }
  };



  const filterRestaurants = () => {
    let filtered = restaurants;
    if (searchTerm) {
      filtered = restaurants.filter(restaurant => 
        restaurant.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        restaurant.location.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }
    setFilteredRestaurants(filtered);
  };

  const handleRestaurantClick = (restaurant) => {
    setSelectedRestaurant(restaurant);
  };

  const handleBackToRestaurants = () => {
    setSelectedRestaurant(null);
  };

  const renderStars = (rating) => {
    const stars = [];
    const fullStars = Math.floor(rating);
    const hasHalfStar = rating % 1 !== 0;

    for (let i = 0; i < fullStars; i++) {
      stars.push(<span key={i} className="text-yellow-400">★</span>);
    }
    if (hasHalfStar) {
      stars.push(<span key="half" className="text-yellow-400">☆</span>);
    }
    for (let i = stars.length; i < 5; i++) {
      stars.push(<span key={i} className="text-gray-300">☆</span>);
    }
    return stars;
  };

  return (
    <div className="min-h-screen bg-gray-100">
      <nav className="bg-blue-600 text-white p-4">
        <div className="container mx-auto flex justify-between items-center">
          <h1 className="text-xl font-bold">SnackSmart - Customer Dashboard</h1>
          <div className="flex items-center space-x-4">
            <span>Welcome, {user.username}!</span>
            <button
              onClick={onLogout}
              className="bg-red-500 px-4 py-2 rounded hover:bg-red-600"
            >
              Logout
            </button>
          </div>
        </div>
      </nav>

      <div className="container mx-auto p-6">
        {!selectedRestaurant ? (
          // Restaurant List View
          <>
            <div className="mb-6">
              <h2 className="text-3xl font-bold mb-4">Discover Restaurants</h2>
              <div className="flex flex-col md:flex-row gap-4">
                <input
                  type="text"
                  placeholder="Search restaurants by name or location..."
                  className="flex-1 px-4 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredRestaurants.map((restaurant) => (
                <div 
                  key={restaurant.restaurantId} 
                  className="bg-white rounded-lg shadow-md overflow-hidden cursor-pointer hover:shadow-lg transition-shadow"
                  onClick={() => handleRestaurantClick(restaurant)}
                >
                  {restaurant.imageUrl && (
                    <img
                      src={restaurant.imageUrl}
                      alt={restaurant.name}
                      className="w-full h-48 object-cover"
                    />
                  )}
                  <div className="p-6">
                    <h3 className="text-xl font-semibold mb-2">{restaurant.name}</h3>
                    <p className="text-gray-600 mb-2">{restaurant.location}</p>
                    <p className="text-gray-600 mb-2">{restaurant.phone}</p>
                    <div className="flex items-center mb-2">
                      <div className="flex mr-2">
                        {renderStars(restaurant.averageRating || 0)}
                      </div>
                      <span className="text-sm text-gray-600">({restaurant.averageRating?.toFixed(1) || '0.0'})</span>
                    </div>
                    <p className="text-gray-500 text-sm mb-3">{restaurant.description}</p>
                    <p className="text-blue-600 font-medium">View Menu →</p>
                  </div>
                </div>
              ))}
            </div>

            {filteredRestaurants.length === 0 && (
              <div className="text-center py-8">
                <p className="text-gray-500">No restaurants found.</p>
              </div>
            )}
          </>
        ) : (
          <RestaurantDetail 
            restaurant={selectedRestaurant} 
            user={user}
            onBack={handleBackToRestaurants}
          />
        )}
      </div>
    </div>
  );
};

export default CustomerDashboard;
